        let repClntRowPosi = ds_repClnt.getRowPosition();

        ds_repClnt.setCellData(repClntRowPosi , "repClnt", rtnList[0]);	//거래처코드
        ds_repClnt.setCellData(repClntRowPosi , "repClntNm", rtnList[1]);	//거래처명
